    id: 'desk-exercises-golf-slice',
    slug: '/desk-exercises-fix-golf-slice/',
    quickAnswerProduct: 'alignment-sticks',
    thumb: 'brown',
    ogImage: 'https://www.cubicalgolfer.com/images/thumbnails/desk-exercises-golf-thumb.webp',
