    updateLog: [{ date: '2026-05-17', note: 'Initial publication' }],
    whoFor: ['Golfers unsure about their shaft flex', 'Anyone buying new clubs', 'Players with inconsistent ball flight'],
    whoSkip: ['Golfers who have been professionally fitted'],
    comparisonTable: {
      caption: 'Shaft Flex by Swing Speed',
      headers: ['Flex', 'Best For', 'Price', 'Driver Speed'],
      rows: [
        { affiliateKey: 'garmin-approach-r10', name: 'Ladies (L)', bestFor: 'Slow swings', price: 'Varies', feature1: 'Under 60 mph', feature2: 'Most flexible' },
        { affiliateKey: 'garmin-approach-r10', name: 'Senior (A)', bestFor: 'Moderate swings', price: 'Varies', feature1: '60-75 mph', feature2: 'Flexible' },
        { affiliateKey: 'garmin-approach-r10', name: 'Regular (R)', bestFor: 'Most golfers', price: 'Varies', feature1: '75-90 mph', feature2: 'Standard', badge: 'MOST COMMON', winner: true },
        { affiliateKey: 'garmin-approach-r10', name: 'Stiff (S)', bestFor: 'Faster swings', price: 'Varies', feature1: '90-105 mph', feature2: 'Firm' },
        { affiliateKey: 'garmin-approach-r10', name: 'X-Stiff (X)', bestFor: 'Tour speed', price: 'Varies', feature1: 'Over 105 mph', feature2: 'Very firm' },
      ],
    },
    sections: [
      { h2: 'Flex Options Explained', body: '<p>Shaft flex ranges from very flexible (Ladies) to very stiff (X-Stiff). Flexible shafts bend more during the downswing, storing and releasing energy. They help slower swingers generate more clubhead speed. Stiffer shafts bend less, giving faster swingers more control and consistency.</p><p>The key insight: flex is about TIMING, not strength. A too-stiff shaft for your speed means the club has not released at impact — the face is open, the ball goes right. A too-flexible shaft means it released early — the face is closed, the ball goes left.</p>' },
      { h2: 'Swing Speed Chart', body: '<table class="cmp-table"><thead><tr><th>Driver Speed</th><th>7-Iron Speed</th><th>Driver Carry</th><th>Recommended Flex</th></tr></thead><tbody><tr><td>Under 60 mph</td><td>Under 50 mph</td><td>Under 140 yd</td><td>Ladies (L)</td></tr><tr><td>60-75 mph</td><td>50-65 mph</td><td>140-180 yd</td><td>Senior (A)</td></tr><tr><td>75-90 mph</td><td>65-80 mph</td><td>180-220 yd</td><td>Regular (R)</td></tr><tr><td>90-105 mph</td><td>80-92 mph</td><td>220-265 yd</td><td>Stiff (S)</td></tr><tr><td>Over 105 mph</td><td>Over 92 mph</td><td>Over 265 yd</td><td>X-Stiff (X)</td></tr></tbody></table><p><strong>Reality check:</strong> the average male amateur swings the driver at 93 mph. That is Regular or borderline Stiff — NOT X-Stiff. Most golfers play shafts that are too stiff because ego tells them to.</p>' },
      { h2: 'How Wrong Flex Hurts Your Game', body: '<p><strong>Too stiff:</strong> ball flies low and right, feels harsh at impact, you lose 5-10 yards because the shaft has not released by impact. Common for golfers who play Stiff when they should play Regular.</p><p><strong>Too flexible:</strong> ball flies high and left, inconsistent dispersion, ballooning trajectory in wind. Common for seniors who still play Regular from when they swung faster 10 years ago.</p>' },
      { h2: 'How to Test Your Speed', body: '<p>The most reliable method: use a <a href="/best-budget-launch-monitor/">launch monitor</a>. The <a href="/best-launch-monitors-no-subscription/">Shot Scope LM1 ($199)</a> displays your speed on a built-in screen. The Garmin R10 ($499) tracks it in the app.</p><p>Free alternative: visit any golf store with a hitting bay (Golf Galaxy, PGA Tour Superstore, Club Champion). Ask them to measure your driver and 7-iron speed. Takes 5 minutes and costs nothing.</p><p>See our <a href="/iron-fitting-guide-beginners/">iron fitting guide</a> for what else gets measured during a fitting.</p>', affiliateKey: 'garmin-approach-r10' },
    ],
    faq: [
      { q: 'What shaft flex should I use?', a: 'Regular for 75-90 mph driver speed (most male golfers). Stiff for 90-105 mph. Senior for under 75 mph. Get measured with a launch monitor for certainty.' },
      { q: 'Does shaft flex really matter?', a: 'Yes — wrong flex costs 5-10 yards and creates inconsistent left-right dispersion. It is one of the highest-impact fitting variables.' },
      { q: 'How do I know if my shaft is too stiff?', a: 'If your shots tend to fly low and right with a harsh feel at impact, your shaft may be too stiff. Try hitting the same club with a Regular flex and compare.' },
    ],
    sources: [{ label: 'USGA — Rules and Equipment', url: 'https://www.usga.org/' }],
